#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool f=0;while(ch<'0'||ch>'9')f^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return f?-res:res;
}
const int N=3e5+10;vector<int> G[N];int n,a[N],tot;long long dp[N],ans=-1e18;
inline void dfs(int u=1,int f=0){dp[u]=a[u];for(int v:G[u])if(v!=f){dfs(v,u);dp[u]+=max(0ll,dp[v]);}ans=max(ans,dp[u]);}
inline void dfs1(int u=1,int f=0){dp[u]=a[u];for(int v:G[u])if(v!=f){dfs1(v,u);dp[u]+=max(0ll,dp[v]);}if(dp[u]==ans)++tot,dp[u]=0;}
int main()
{
	n=read();rep(1,n,i)a[i]=read();
	rep(2,n,i)
	{
		int u=read(),v=read();
		G[u].push_back(v);G[v].push_back(u);
	}
	dfs();dfs1();printf("%lld %d\n",1ll*ans*tot,tot);
}
